@p7 = external hidden addrspace(7) global i8

define i64 @constexpr_as_cast(i1 %c) {
entry:
  %p0 = tail call ptr @malloc(i64 64)
  %select = select i1 %c, ptr %p0, ptr addrspacecast (ptr addrspace(7) getelementptr inbounds (i8, ptr addrspace(7) @p7, i32 1) to ptr)
  %calc_size = tail call i64 @llvm.objectsize.i64.p0(ptr %select, i1 false, i1 true, i1 true)
  ret i64 %calc_size
